const body = $input.first().json.body || {};
const message = (body.message || '').trim();
const session_id = (body.session_id || 'math-default').trim();

// Health-check: отдаём pong без вызова LLM
if (message === 'ping') {
  return [{json: {valid: 0, error: 'pong'}}];
}

if (!message || message.length < 2) {
  return [{json: {valid: 0, error: 'Введите сообщение'}}];
}

if (message.length > 100000) {
  return [{json: {valid: 0, error: 'Слишком длинный запрос (максимум 100000 символов)'}}];
}

return [{json: {valid: 1, message: message, session_id: session_id}}];

const message = $('Агрегация').first().json.message;
const historyContext = $('Агрегация').first().json.historyContext || '';
const session_id = $('Агрегация').first().json.session_id || 'math-default';
const lower = message.toLowerCase();

const mathKeywords = [
  'посчитай', 'вычисли', 'вычислить', 'рассчитай', 'рассчитать',
  'реши', 'решить', 'решение', 'уравнен', 'неравенств',
  'формул', 'процент', 'корень', 'степен', 'логарифм',
  'сумм', 'разност', 'произведен', 'делен', 'остаток от',
  'площад', 'объём', 'объем', 'периметр', 'окружност',
  'треугольник', 'квадрат', 'куб', 'прямоугольник', 'цилиндр', 'сфер',
  'интеграл', 'производн', 'предел', 'синус', 'косинус', 'тангенс',
  'матриц', 'вектор', 'определител', 'детерминант',
  'график', 'функци', 'парабол',
  'статистик', 'среднее', 'медиан', 'дисперс', 'отклонен',
  'вероятност', 'комбинатор', 'факториал', 'перестанов', 'сочетан',
  'npv', 'irr', 'roi', 'аннуитет', 'ипотек', 'кредит', 'депозит',
  'инвестиц', 'маржа', 'наценк', 'скидк', 'ндс', 'налог',
  'зарплат', 'рентабельн', 'прибыл', 'выручк', 'себестоимост',
  'сколько будет', 'чему равн', 'найди', 'найти',
  'sqrt', 'calculate', 'solve', 'equation', 'math',
  'конвертируй', 'переведи в'
];

const hasMathExpression = /\d+\s*[+\-*/^%=]\s*\d+/.test(message);
const hasNumbers = /\d{2,}/.test(message) || /\d+[.,]\d+/.test(message);

let isMath = hasMathExpression;

if (!isMath) {
  for (const kw of mathKeywords) {
    if (lower.includes(kw)) { isMath = true; break; }
  }
}

if (!isMath && hasNumbers && message.length > 20) {
  const taskIndicators = ['сколько', 'какой', 'какая', 'какое', 'найди', 'найти',
    'определи', 'определить', 'если', 'при', 'дано', 'равно', 'равна'];
  for (const kw of taskIndicators) {
    if (lower.includes(kw)) { isMath = true; break; }
  }
}

if (!isMath && /^[\d\s+\-*/^().,]+$/.test(message.trim())) {
  isMath = true;
}

if (!isMath) {
  return [{ json: { message, mode: 'general', historyContext, session_id } }];
}

return [{ json: { message, mode: 'math', historyContext, session_id } }];

try {
  const raw = $input.first().json;
  if (raw.error) {
    return [{ json: { response: 'Не удалось обработать запрос. Попробуйте ещё раз.', code: '', raw_result: '' } }];
  }
  const text = raw.output[0].content[0].text;
  return [{ json: { response: text.trim(), code: '', raw_result: '' } }];
} catch(e) {
  return [{ json: { response: 'Ошибка обработки.', code: '', raw_result: '' } }];
}

try {
  const raw = $input.first().json;

  if (raw.error) {
    return [{ json: { success: 0, code: '', error: 'GigaChat недоступен. Попробуйте позже.' } }];
  }

  let code = raw.output[0].content[0].text;

  // Убираем markdown-обёртки
  code = code.replace(/```python\s*/gi, '').replace(/```\s*/g, '').trim();

  // Убираем текст до первого import или первой переменной
  const lines = code.split('\n');
  let startIdx = 0;
  for (let i = 0; i < lines.length; i++) {
    const line = lines[i].trim();
    if (line.startsWith('import ') || line.startsWith('from ') ||
        line.match(/^[a-zA-Z_]/) || line.startsWith('#') ||
        line.startsWith('print(')) {
      startIdx = i;
      break;
    }
  }
  code = lines.slice(startIdx).join('\n').trim();

  if (!code || code.length < 5) {
    return [{ json: { success: 0, code: '', error: 'GigaChat не смог сгенерировать код.' } }];
  }

  // ПРОВЕРКА БЕЗОПАСНОСТИ
  // Допускаются sympy/numpy/scipy — Pyodide их песочница безопасна
  // (no fs / no net), а импорт самих модулей не даёт доступа к системе.
  const dangerous = [
    'import os', 'import sys', 'import subprocess', 'import shutil',
    'import pathlib', 'import socket', 'import http', 'import requests',
    'import urllib', 'import ftplib', 'import smtplib', 'import pickle',
    'open(', 'exec(', 'eval(', '__import__', 'compile(',
    'globals(', 'locals(', 'getattr(', 'setattr(', 'delattr(',
    'os.', 'sys.', 'subprocess.', 'shutil.', 'pathlib.',
    'socket.', 'requests.', 'input('
  ];

  const codeLower = code.toLowerCase();
  for (const d of dangerous) {
    if (codeLower.includes(d.toLowerCase())) {
      return [{ json: { success: 0, code: code, error: 'Код содержит запрещённую операцию: ' + d } }];
    }
  }

  if (!code.includes('print(') && !code.includes('print (')) {
    code += '\nprint(result)';
  }

  return [{ json: { success: 1, code: code, error: '' } }];

} catch (e) {
  return [{ json: { success: 0, code: '', error: 'Ошибка обработки ответа GigaChat: ' + e.message } }];
}

const historyRows = $input.all().reverse();
let historyContext = '';
if (historyRows.length > 0) {
  const lines = historyRows.map(item => {
    const role = item.json.role === 'user' ? 'Пользователь' : 'Ассистент';
    return role + ': ' + (item.json.content || '');
  });
  historyContext = 'История диалога:\n' + lines.join('\n') + '\n\n';
}
const v = $('Валидация').first().json;
return [{json: {message: v.message, session_id: v.session_id, historyContext: historyContext}}];

// Phase 2 — фронт уже исполнил Python в Pyodide и шлёт результат.
// Достаём поля и нормализуем. final_line — это значение после маркера
// «ОТВЕТ: », отделённое от полного raw_result для удобства подстановки.
const body = $input.first().json.body || {};
return [{json: {
  message: (body.message || '').trim(),
  session_id: (body.session_id || 'math-default').trim(),
  code: body.code || '',
  raw_result: body.raw_result || '',
  final_line: (body.final_line || '').trim(),
  exec_error: body.error || ''
}}];

