// Сборка финального ответа MATH детерминированно:
//   число берём из final_line (= вывод Pyodide), пояснение — от LLM.
// Если Pyodide сломался (exec_error не пустой), возвращаем ошибку и не
// дёргаем LLM-пояснение как итог — оно не имеет смысла без результата.
try {
  const raw = $input.first().json;
  const prev = $('Извлечение полей').first().json;

  // Ошибка исполнения Python
  if (prev.exec_error) {
    return [{ json: { response_text: 'Не удалось решить — Python завершился с ошибкой:\n' + prev.exec_error } }];
  }

  const finalLine = (prev.final_line || prev.raw_result || '').trim();
  if (!finalLine) {
    return [{ json: { response_text: 'Код выполнился, но не вернул значение.' } }];
  }

  // Извлекаем пояснение LLM (может быть отсутствует — таймаут / GigaChat недоступен)
  let explanation = '';
  try {
    explanation = raw.output[0].content[0].text.trim();
  } catch (e) {
    explanation = '';
  }

  // Защита: если LLM всё-таки начала с «Ответ: ...» — срезаем эту шапку,
  // чтобы не было дубликата числа в финальном ответе.
  explanation = explanation
    .replace(/^Ответ\s*[:\-]\s*[^\n.]+[.\n]\s*/i, '')
    .replace(/^Итак[,]?\s*получаем[^\n.]+[.\n]\s*/i, '')
    .trim();

  let response = 'Ответ: ' + finalLine;
  if (explanation) {
    response += '\n\n' + explanation;
  }

  return [{ json: { response_text: response } }];
} catch (e) {
  const prev = $('Извлечение полей').first().json;
  if (prev && prev.final_line) {
    return [{ json: { response_text: 'Ответ: ' + prev.final_line } }];
  }
  if (prev && prev.raw_result) {
    return [{ json: { response_text: 'Ответ: ' + prev.raw_result } }];
  }
  return [{ json: { response_text: 'Ошибка обработки.' } }];
}
